import{_ as a,o as t,c as s,ag as i}from"./chunks/framework.DTiDeF2Q.js";const u=JSON.parse('{"title":"Paths | Dotfiles (ES)","titleTemplate":":title","description":"Cómo Dotfiles gestiona tu jerarquía PATH para cargar las herramientas correctas en el orden correcto.","frontmatter":{"title":"Paths | Dotfiles","description":"Cómo Dotfiles gestiona tu jerarquía PATH para cargar las herramientas correctas en el orden correcto.","lang":"es-ES","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Paths preview","canonical":"/es/paths/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Paths","pageType":"docs","schemaType":"WebPage","metaTitle":"Paths - Dotfiles (ES)","permalink":"/es/paths/","meta":[{"name":"keywords","content":"path, entorno, variables, jerarquía, dotfiles, chezmoi, shell, configuración"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Cómo Dotfiles gestiona tu jerarquía PATH para cargar las herramientas correctas en el orden correcto."},{"name":"twitter:title","content":"Paths - Dotfiles"},{"name":"og:title","content":"Paths - Dotfiles"},{"name":"og:description","content":"Cómo Dotfiles gestiona tu jerarquía PATH para cargar las herramientas correctas en el orden correcto."},{"name":"og:image:alt","content":"Dotfiles - Diseñado para tu vida en el shell"},{"name":"og:locale","content":"es_ES"}]},"headers":[],"relativePath":"es/paths/index.md","filePath":"es/paths/index.md","lastUpdated":1773010926000}'),r={name:"es/paths/index.md"};function o(l,e,n,c,d,h){return t(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="paths" tabindex="-1">Paths <a class="header-anchor" href="#paths" aria-label="Permalink to &quot;Paths&quot;">​</a></h1><p>Gestión modular del <code>PATH</code>. Asegura que las herramientas correctas se carguen en el orden correcto.</p><h2 id="descubrir" tabindex="-1">Descubrir <a class="header-anchor" href="#descubrir" aria-label="Permalink to &quot;Descubrir&quot;">​</a></h2><p>Las configuraciones de ruta se dividen en archivos por prioridad. Durante <code>chezmoi apply</code>:</p><ol><li>Los archivos del directorio se recorren alfabéticamente</li><li>El contenido se agrega en <code>~/.config/shell/paths.sh</code></li><li>Se carga desde <code>.zshrc</code> al iniciar</li></ol><h2 id="referencia" tabindex="-1">Referencia <a class="header-anchor" href="#referencia" aria-label="Permalink to &quot;Referencia&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Script</th><th style="text-align:left;">Descripción</th></tr></thead><tbody><tr><td style="text-align:left;"><code>00-default.paths.sh</code></td><td style="text-align:left;">Rutas base del sistema (<code>/usr/bin</code>, <code>/sbin</code>) y Homebrew. Se carga primero.</td></tr><tr><td style="text-align:left;"><code>99-custom.paths.sh</code></td><td style="text-align:left;">Rutas personalizadas del usuario (SDKs, bins locales). Se carga al final para prioridad.</td></tr></tbody></table><h2 id="empezar" tabindex="-1">Empezar <a class="header-anchor" href="#empezar" aria-label="Permalink to &quot;Empezar&quot;">​</a></h2><h3 id="anadir-una-ruta-de-usuario" tabindex="-1">Añadir una ruta de usuario <a class="header-anchor" href="#anadir-una-ruta-de-usuario" aria-label="Permalink to &quot;Añadir una ruta de usuario&quot;">​</a></h3><ol><li>Edita <code>99-custom.paths.sh</code> o crea un archivo nuevo (por ejemplo <code>50-miproyecto.paths.sh</code>)</li><li>Añade tu ruta:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PATH</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:/ruta/a/dir&quot;</span></span></code></pre></div></li><li>Aplica los cambios:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chezmoi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span></span></code></pre></div></li><li>Verifica:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $PATH</span></span></code></pre></div></li></ol>',10)])])}const g=a(r,[["render",o]]);export{u as __pageData,g as default};
